const Q_ECONOMICS_2023_MODEL_II=[{"id": "objective>Economics>2023 Model II>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">All of the following describes conditions necessary for existence of a perfect market EXCEPT</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lack of homogeneity of goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">large buyers and sellers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">perfect knowledge</div>", "<div style=\"font-family:Cambria;font-size:17px;\">portability of goods</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">lack of homogeneity of goods is not a characteristics or features of a perfect market. The features/ characteristics are: perfect knowledge about the market, there is free entry and exit, there are large number of buyers and sellers, the goods are portable and homogeneous, there is no preferential treatment etc.</div>", "topic": "MARKET STRUCTURE : MEANING OF MARKET & TYPES"}, {"id": "objective>Economics>2023 Model II>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given the table demonstrating the law of diminishing marginal utility below, what is the value of X?  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">No. of oranges Consumed</td><td style=\"border:1px solid black;text-align:center;\">\tTotal Utility</td><td style=\"border:1px solid black;text-align:center;\">\tAverage Utility</td><td style=\"border:1px solid black;text-align:center;\">\tMarginal Utility\t</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">1\t</td><td style=\"border:1px solid black;text-align:center;\">9</td><td style=\"border:1px solid black;text-align:center;\">\t9</td><td style=\"border:1px solid black;text-align:center;\">\t-\t</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">2\t</td><td style=\"border:1px solid black;text-align:center;\">16</td><td style=\"border:1px solid black;text-align:center;\">\t8\t</td><td style=\"border:1px solid black;text-align:center;\">X\t</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">3\t</td><td style=\"border:1px solid black;text-align:center;\">24</td><td style=\"border:1px solid black;text-align:center;\">\t8\t</td><td style=\"border:1px solid black;text-align:center;\">6\t</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">4\t</td><td style=\"border:1px solid black;text-align:center;\">30</td><td style=\"border:1px solid black;text-align:center;\">\t7.5</td><td style=\"border:1px solid black;text-align:center;\">\t4\t</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">5\t</td><td style=\"border:1px solid black;text-align:center;\">34\t</td><td style=\"border:1px solid black;text-align:center;\">6.8</td><td style=\"border:1px solid black;text-align:center;\">\tY\t</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">6\t</td><td style=\"border:1px solid black;text-align:center;\">36</td><td style=\"border:1px solid black;text-align:center;\">\t6</td><td style=\"border:1px solid black;text-align:center;\">\t2\t</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">7\t</td><td style=\"border:1px solid black;text-align:center;\">36</td><td style=\"border:1px solid black;text-align:center;\">\t5.1</td><td style=\"border:1px solid black;text-align:center;\">\t0\t</td></tr></table></div></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Marginal Utility is the additional satisfaction a consumer gains from consuming one more unit of a good or service. It can be calculated by subtracting the total utility of the previous consumption from the total utility of the current consumption. In this case, the total utility of consuming 2 oranges is 16 and the total utility of consuming 1 orange is 9. Therefore, the marginal utility (X) of the second orange is 16 - 9 = 7.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : DIMINISHING MARGINAL UTILITY AND LAW OF DEMAND"}, {"id": "objective>Economics>2023 Model II>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Economics is often described as a science because it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">employs the use of laboratory experiments</div>", "<div style=\"font-family:Cambria;font-size:17px;\">engages accurate predication of human beings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">make use of controlled experiments</div>", "<div style=\"font-family:Cambria;font-size:17px;\">use scientific methods to explain observed phenomena</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Economics is regarded as a science because it uses scientific methods to build theories that can help explain behaviour of individuals, groups and organisations. </div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : SCIENTIFIC APPROACH"}, {"id": "objective>Economics>2023 Model II>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">From the graph below, Point \"E\" shows--------------  <br/>    <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">productive efficiency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">allocative efficiency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">product inefficiency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">product efficiency</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Point 'E\" inside the graph indicates it is technologically inefficient\" , Underemployed\" or wide spread unemployent\" or resources are not fully utilized or production inefficient\"</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONCEPT"}, {"id": "objective>Economics>2023 Model II>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">40 men were employed in a farm, and they produced an average of 30 tonnes of cassava per person. Calculate the total product.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1,100 tonnes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1,300 tonnes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1,400 tonnes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1,200 tonnes</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The total product can be calculated by multiplying the number of workers by the average product per worker. In this case, 40 men produced an average of 30 tonnes of cassava each. Therefore, the total product is 40 men * 30 tonnes/man = 1,200 tonnes.</div>", "topic": "THEORY OF PRODUCTION (1) : INTRODUCTION"}, {"id": "objective>Economics>2023 Model II>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Economists refer to private goods as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">non rival and non- excludable</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rivalrous and excludable</div>", "<div style=\"font-family:Cambria;font-size:17px;\">non rival and excludable</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rivalrous and non-excludable</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">They are goods that are divisible and to which principle of exclusion is fully applied. It is based on the following assumptions: Ability to pay, Rivalry in consumption, price is its basis, willingness to pay etc.</div>", "topic": "PUBLIC FINANCE : INTRODUCTION"}, {"id": "objective>Economics>2023 Model II>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If demand function for a product is Qd = 30 - 4P, and the price and quantity of products is 4 and 14 respectively. What is the price elasticity of demand for the product?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.14</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.7</div>", "<div style=\"font-family:Cambria;font-size:17px;\">14.1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.1</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Q = 14, P = 4  <br/>  <br/> Qd = 30 - 4p  <br/>  <br/> ∆q/∆p = - 4  <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">ed</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">∆q<hr size=\"1\" />∆p</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">p<hr size=\"1\" />q</td><td style=\"text-align:center;\"> </td></tr></table></div> <br/>  <br/> = - 4 x 4/14  <br/>  <br/> ed = -1.14  <br/> Since price elasticity is positive, then Ed = 1.14</div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>2023 Model II>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The decision to consume more of one product under normal circumstances will apply </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">more of another product will be consumed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">less of the product will be consumed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">no other products will be consumed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">less of another product will be consumed</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Getting more of one commodity allows a consumer to demand less of the other product. The demand for substitute products shows a negative correlation. That is, consumption of one product reduces or replaces the need for the other.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER EQUILIBRIUM"}, {"id": "objective>Economics>2023 Model II>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a kilogram of carrot is #8.00, 20 kilograms are demanded and when the price decreased to #6.000 per kilogram, 30 kilograms are demanded. The elasticity of demand equals to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">11</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />2</td></tr></table></div></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">e</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">∆Q<hr size=\"1\" />∆P</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">P<hr size=\"1\" />Q</td><td style=\"text-align:center;\"></td></tr></table></div> <br/>  <br/> where ∆Q = Q2 - Q1 and ∆P = P2 - P1  <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">e</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">30 - 20<hr size=\"1\" /> 6 - 8 </td><td style=\"text-align:center;\"> x</td><td style=\"text-align:center;\">8<hr size=\"1\" />20</td><td style=\"text-align:center;\"></td></tr></table></div> <br/>  <br/> = -2 since price elasticity of demand is always positive, then e = 2</div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>2023 Model II>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The quantity of commodity a consumer is willing and able to buy at a particular time is called </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">desire</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wish</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Demand for a commodity is its quantity which consumers are willing and able to buy at various prices during a given period of time.</div>", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2023 Model II>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Suppose the public expenditure as a percentage of GDP of four countries is shown in the table below  <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">A\t</td><td style=\"border:1px solid black;text-align:center;\">40%\t</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">B\t</td><td style=\"border:1px solid black;text-align:center;\">50%\t</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">C\t</td><td style=\"border:1px solid black;text-align:center;\">33%\t</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">D\t</td><td style=\"border:1px solid black;text-align:center;\">36%\t</td></tr></table></div> <br/> Which type of economy exists in these countries?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mixed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Planned</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pure market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Traditional</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The economy is mixed with the highest GDP. It constitutes private expenditure as percentage of GDP.</div>", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM"}, {"id": "objective>Economics>2023 Model II>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following shows why individual demand curve for a good usually slopes downward from left to right?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">More of commodities are offered for sale at a lower than higher prices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Prices are usually falling when demand is low</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Marginal utility falls as consumption increases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The higher the price, the higher the quantity offered for sale</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The individual demand curve for a good usually slopes downward from left to right because of the law of diminishing marginal utility. This law states that as a person increases consumption of a product while keeping consumption of other products constant, there is a decline in the marginal utility that person derives from consuming each additional unit of that product. In simpler terms, the more of a good or service a consumer uses, the less benefit or satisfaction they get from each additional unit of consumption. Therefore, consumers are willing to pay less for each additional unit, which is why the demand curve slopes downward.</div>", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2023 Model II>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Identify one of the following which can NOT be used to close deflationary gap</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Increase government expenditure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Reduction in taxes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Increased money supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Increased interest rate</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">- Monetary policy is implemented by reducing the interest rates in the economy in order to increase the supply of money to enhance growth.  <br/>  <br/> - The fiscal policy is implemented by the reduction of taxes and increasing government spending in order to boost demand.  <br/>  <br/> - Policymakers may choose to implement a stabilization policy to close the recessionary gap and increase real GDP. </div>", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL"}, {"id": "objective>Economics>2023 Model II>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following will cause an increase in cost of production?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Hyper-inflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Demand pull inflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cost push inflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Structural inflation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cost push inflation occurs when overall prices increase(inflation) due to increases in the cost of wages and raw materials. It can also occur when higher costs of production decrease the aggregate supply in the economy.</div>", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL"}, {"id": "objective>Economics>2023 Model II>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Institutions serving as links between surplus and deficit units can be identified as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">financial intermediates</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tax officers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">acceptance houses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pension offices</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A financial intermediary is typically an institution that facilitates the channeling of funds between lenders and borrowers indirectly.</div>", "topic": "FINANCIAL INSTITUTION : INTRODUCTION"}, {"id": "objective>Economics>2023 Model II>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the equilibrium level of national income (Y) where Y = C + I + G; C = 100 + 0.75Y; I = 50; G = 200</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">100</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1400</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1500</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2000</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Y</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">a + I + G <hr size=\"1\" /> 1 - b</td><td style=\"text-align:center;\"></td></tr></table></div> <br/>  <br/> where b = 0.75  <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">100 + 50 + 200<hr size=\"1\" />1 - 075</td></tr></table></div>  <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">350<hr size=\"1\" />0.25</td><td style=\"text-align:center;\"></td></tr></table></div> <br/>  <br/> = 1400  <br/>  <br/> <strong>Alternatively</strong>:  <br/> Y = C + I + G  <br/> Y = 100 + 0.75Y + 50 + 200  <br/> Y - 0.75Y = 350  <br/> Y( 1 - 0.75) = 350  <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Y</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">350<hr size=\"1\" />0.25</td><td style=\"text-align:center;\"></td></tr></table></div> <br/>  <br/> Y = 1400</div>", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : ELEMENTARY THEORY OF INCOME DETERMINATION"}, {"id": "objective>Economics>2023 Model II>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A persistence rise in the prices of inputs will lead to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hyperinflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stagflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cost push inflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">demand pull inflation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cost push inflation is inflation caused by an increase in prices of inputs like labour, raw materials etc.</div>", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL"}, {"id": "objective>Economics>2023 Model II>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The number of people who are qualified to work and who offered themselves for employment are called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">migrant labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">working population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">labour turnover</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mobility of labour</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">working population also known as labour force refers to the total number of persons available to supply the labour for the production of economic goods and service. In other words, it is the total number of people of working age in a country who are able and willing by law to work.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : SUPPLY OF LABOUR"}, {"id": "objective>Economics>2023 Model II>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Overpopulation is caused by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">disease</div>", "<div style=\"font-family:Cambria;font-size:17px;\">emigration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">low Literacy rates</div>", "<div style=\"font-family:Cambria;font-size:17px;\">war and conflicts</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Overpopulation is caused by a variety of factors, one of which is low literacy rates. When the literacy rate is low, people are less likely to understand the implications of having many children, leading to a high birth rate and overpopulation. Disease, emigration, war and conflicts can actually lead to a decrease in population rather than overpopulation.</div>", "topic": "POPULATION : OVER POPULATION, UNDER POPULATION"}, {"id": "objective>Economics>2023 Model II>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is the resultant effect of a fall in the profit margin of producers in an economy?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Unemployment will increase</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Unemployment will fall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Unemployment will remain constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Unemployment will fluctuate</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In general, Okun's findings demonstrated that when unemployment falls, the production of a country will increase and vice versa.</div>", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY"}, {"id": "objective>Economics>2023 Model II>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Multiplier can be described as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the ratio of change in an endogenous variable to the change spending</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the ratio of change in output to a change in autonomous spending</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the ratio of variables that multiplies autonomous spending plus tax</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the ratio of variables that multiplies autonomous spending</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In economics, the multiplier effect refers to the increase in final income arising from any new injection of spending. The size of the multiplier depends upon household's marginal decisions to spend, called the marginal propensity to consume or MPC, or to save, called the marginal propensity to save or MPS. So, it is the ratio of change in output to a change in autonomous spending.</div>", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : THE CONCEPT OF MULTIPLIER"}, {"id": "objective>Economics>2023 Model II>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following must be true to have a closed economy with no government, and yet the value of the investmet multiplier still increase?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Actual saving has fallen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Marginal propensity to save has fallen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Actual investment had fallen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Average propensity to invest has fallen</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Investment multiplier (K) is a function of two factors; The MPS and MPC. If MPC is high, K will also be high but if MPC is low, K will also be low. on the other hand, If MPS is high, K will be low and if MPS is low, K will be high ( since there is an inverse relationship between MPS and K).</div>", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : SAVINGS FUNCTION"}, {"id": "objective>Economics>2023 Model II>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following would not be a reason for a government to impose a quota on imports?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">To support strategic industry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">To decrease tax revenue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">To prevent dumping</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Employment oppourtunity</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Reasons for the imposition of tariffs or restriction of trade are: To protect infant industries, generation of revenue, to prevent dumping, to improve balance of payment deficit, employment generation, to promote self-sufficiency, political motive, to protect strategic industries etc.</div>", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE"}, {"id": "objective>Economics>2023 Model II>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a two by two model of international trade, it is assumed that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">both countries could gain from trade at the same time, but the volume of the gains depends on terms of trade</div>", "<div style=\"font-family:Cambria;font-size:17px;\">both countries could gain from trade at the same time, and the volume of the gains does not depend on terms of trade</div>", "<div style=\"font-family:Cambria;font-size:17px;\">both countries could gain from trade at the same time, but term of trade is inconsequential for the distribution of the gains</div>", "<div style=\"font-family:Cambria;font-size:17px;\">neither country could ever gain from trade since term of trade is depends on the distribution of the gains from trade</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The model emphasizes the export of goods requiring factors of production that a country has in abundance. It also emphasizes the import of goods that a nation cannot produce as efficiently. It takes the position that countries should ideally export materials and resources of which they have an excess, while proportionately importing those resources they need.</div>", "topic": "INTERNATIONAL TRADE : TERMS OF TRADE"}, {"id": "objective>Economics>2023 Model II>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Agriculture accounts for about 60% of the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">active labour force in West Africa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">arable land in West Africa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">service sector activities in West Africa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">commodity market in West Africa</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Agriculture accounts for about 60% of the active labour force in West Africa. This is because a large portion of the population in West Africa is engaged in farming and other agricultural activities for their livelihood. The other options are incorrect as agriculture does not account for 60% of the arable land, service sector activities, or the commodity market in West Africa.</div>", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION"}, {"id": "objective>Economics>2023 Model II>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is NOT one of the characteristics of developing countries?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">High capital formation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Low saving</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mono- product economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">High unemployment</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Developing countries are characterized by low capital formation, not high. Capital formation refers to the production of capital goods, such as plants, machinery, tools, etc., that are used in the production of other goods. These are typically low in developing countries due to factors such as low savings, low investment, and lack of advanced technology.</div>", "topic": "ECONOMIC DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT"}, {"id": "objective>Economics>2023 Model II>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which one of the following measures the natural growth rate of population?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Birth</td><td style=\"text-align:center;\">rate</td><td style=\"text-align:center;\"><hr size=\"1\" /></td><td style=\"text-align:center;\">Death</td><td style=\"text-align:center;\">rate</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Birth + Net migration = Death</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Natural increase - Birth rate + Net migration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Birth rate - Death rate</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The natural growth rate of a population is measured by the difference between the birth rate and the death rate. This is because the birth rate indicates the number of births in a population, while the death rate indicates the number of deaths. The difference between these two rates gives the natural increase or decrease in the population, without considering migration.</div>", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE"}, {"id": "objective>Economics>2023 Model II>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Indicator of underdevelopment is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">low per capita income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">low population growth rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high life expectancy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">low birth rate</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The indicators of underdevelopment include: high birth rates, high infant mortality, low per capita GDP, high levels of illiteracy, and low life expectancy.</div>", "topic": "ECONOMIC DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT"}, {"id": "objective>Economics>2023 Model II>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A period of economic stagnation accompanied by rising inflation can create</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hyper-inflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">creeping inflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stagflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">depression</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Stagflation is a situation in which the growth rate is slow with a high rise in inflation. It also occurs when an economic is stagnant with inflation.</div>", "topic": "INFLATION & DEFLATION : TYPES"}, {"id": "objective>Economics>2023 Model II>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The rate of output per worker (or group of workers) per unit time is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">labour productivity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">total output</div>", "<div style=\"font-family:Cambria;font-size:17px;\">workdone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">individual output</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The rate of output per worker (or group of workers) per unit time is referred to as labour productivity. It is a measure of the efficiency of a worker or group of workers in converting inputs into goods and services. It is calculated by dividing the total output by the total input (labour hours).</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : INTRODUCTION"}, {"id": "objective>Economics>2023 Model II>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The economies of West African Countries depend majorly on</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">primary product</div>", "<div style=\"font-family:Cambria;font-size:17px;\">secondary product</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tertiary product</div>", "<div style=\"font-family:Cambria;font-size:17px;\">manufacturing product</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The economies of West African Countries depend majorly on primary products. Primary products refer to goods that are available from cultivating plants or by extracting minerals from the earth. These include agricultural products, mining products, and other raw materials. West African countries like Nigeria, Ghana, and Ivory Coast are known for their export of primary products like oil, cocoa, and gold respectively.</div>", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION"}, {"id": "objective>Economics>2023 Model II>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Macroeconomics focuses on the following units in an aggregative manner </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">individual consumers, individual firms, government and external sector</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government, household firms, individual consumers and external sector</div>", "<div style=\"font-family:Cambria;font-size:17px;\">household, firms, government, corporate sector and external sector</div>", "<div style=\"font-family:Cambria;font-size:17px;\">individual consumers, household firms and manufacturing sector</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Macroeconomics is a branch of economics that studies the behavior and performance of an economy as a whole. It focuses on the aggregate changes in the economy such as unemployment, growth rate, gross domestic product and inflation. The units it focuses on in an aggregative manner are households, firms, government, corporate sector and external sector.</div>", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS"}, {"id": "objective>Economics>2023 Model II>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following Age group belongs to active Labour force?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0 - 17yrs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15 - 25yrs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">65yrs and above</div>", "<div style=\"font-family:Cambria;font-size:17px;\">18 - 64yrs</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">18 - 64yrs Age group belongs to active Labour force (working population or active population) in a country.</div>", "topic": "POPULATION : POPULATION STRUCTURE/ DISTRIBUTION"}, {"id": "objective>Economics>2023 Model II>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An increase in nominal income without increase in price will result to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increased real income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreased real income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increased GDP</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreased GNP</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When nominal income increases without any change to prices, this means consumers can purchase more goods at the same price, and for most goods, consumers will demand more.</div>", "topic": "INFLATION & DEFLATION : EFFECT"}, {"id": "objective>Economics>2023 Model II>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">------------- is NOT the cause of balance of payments (BOP) deficits in Nigeria</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Poor performance of non-oil sector</div>", "<div style=\"font-family:Cambria;font-size:17px;\">No import substitution strategies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">High servicing of debt</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Export promotion</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Balance of payments (BOP) is a record of all economic transactions between the residents of a country and the rest of the world in a particular period. BOP deficits occur when the value of imports and outflows of capital exceed the value of exports and capital inflows. Export promotion is a strategy aimed at encouraging the goods and services of a country to be sold in the international market. Therefore, export promotion is not a cause of BOP deficits, but rather a solution to it.</div>", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT"}, {"id": "objective>Economics>2023 Model II>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the supply curve of labour market is given as S = 4L + 8. What is L when s = 20?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The supply curve of labour market is given as S = 4L + 8. To find the value of L when S = 20, we substitute S = 20 in the equation and solve for L. This gives us L = 3.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : SUPPLY OF LABOUR"}, {"id": "objective>Economics>2023 Model II>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The diagram above represent</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cyclical unemployment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">structural unemployment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">frictional unemployment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">volunatary unempployment</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The dotted line in the graph above represent the upturn and downturn of the econonmy. Therefore, the diagram is cyclical unemployment.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : THE CONCEPT OF UNEMPLOYMENT"}, {"id": "objective>Economics>2023 Model II>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> From the graph above, the consumer is at equilibrium at point</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">j</div>", "<div style=\"font-family:Cambria;font-size:17px;\">k</div>", "<div style=\"font-family:Cambria;font-size:17px;\">l</div>", "<div style=\"font-family:Cambria;font-size:17px;\">m</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The consumer is at equilibrium is at point k where the slope of the indifference curve is tangential to the budget line.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER EQUILIBRIUM"}, {"id": "objective>Economics>2023 Model II>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The diagram above represent</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Production possibility curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Supply curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">indifference curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Demand curve</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The digram above represent the production possibility curve which is also known as production possibility frontier, production possibility boundary, or transformation curve.</div>", "topic": "INTRODUCTION TO ECONOMICS : PRODUCTION POSSIBILITY CURVE"}, {"id": "objective>Economics>2023 Model II>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Nigerian indigenization decree was promulgated in order to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">allow indigenes to have the full participation in the economic activities of the country</div>", "<div style=\"font-family:Cambria;font-size:17px;\">drive away foreigners</div>", "<div style=\"font-family:Cambria;font-size:17px;\">give equal chances to indigenes and foreigners in making economic decisions in the country</div>", "<div style=\"font-family:Cambria;font-size:17px;\">give industrial training to indigenes</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Nigerian Indigenization Decree was promulgated in order to allow indigenes to have the full participation in the economic activities of the country. <br/>  <br/> The decree was passed in 1972, shortly after Nigeria gained independence from Great Britain. At the time, the Nigerian economy was dominated by foreign companies. The decree was designed to increase the participation of Nigerians in the economy by requiring foreign companies to sell a portion of their shares to Nigerian citizens.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INDIGENISATION & NATIONALISATION"}];
